import React, { useState } from 'react';

export default function Arr(){
    const [showAll, setShow] = useState(1);
    //  const clickToSetShow= () => {
    //     if(!showAll){
    //         setShow(true);
    //     }else{
    //         setShow(false);
    //     }
    //  }
    const clickToSetShow= () => {
        setShow(showAll+1);
        console.log(showAll)
    }
    return (
        <>
         <div className="ARR-area container">
            <div className="ARR-area-head">
                <h3>New Arrivals</h3>
                <div className="menu-skip">
                    <p onClick={clickToSetShow}>Xem thêm</p> 
                </div>
            </div>
            <div className="ARR-area-body">
                <ul className="list-ARR">
                    <li> <img src="https://render.fineartamerica.com/images/rendered/default/poster/8/10/break/images/artworkimages/medium/3/3-csgo-putri-anggi.jpg"></img></li>
                    <li> <img src="https://render.fineartamerica.com/images/rendered/default/poster/8/10/break/images/artworkimages/medium/3/3-csgo-putri-anggi.jpg"></img></li>
                    <li> <img src="https://render.fineartamerica.com/images/rendered/default/poster/8/10/break/images/artworkimages/medium/3/3-csgo-putri-anggi.jpg"></img></li>
                    <li> <img src="https://render.fineartamerica.com/images/rendered/default/poster/8/10/break/images/artworkimages/medium/3/3-csgo-putri-anggi.jpg"></img></li>
                    {showAll+1 && (
                        <>  
                            <li> <img src="https://render.fineartamerica.com/images/rendered/default/poster/8/10/break/images/artworkimages/medium/3/3-csgo-putri-anggi.jpg"></img></li>
                            <li> <img src="https://render.fineartamerica.com/images/rendered/default/poster/8/10/break/images/artworkimages/medium/3/3-csgo-putri-anggi.jpg"></img></li>
                            <li> <img src="https://render.fineartamerica.com/images/rendered/default/poster/8/10/break/images/artworkimages/medium/3/3-csgo-putri-anggi.jpg"></img></li>
                            <li> <img src="https://render.fineartamerica.com/images/rendered/default/poster/8/10/break/images/artworkimages/medium/3/3-csgo-putri-anggi.jpg"></img></li>
                        </>
                    )}
                    {Array.from({ length: 4 }).map((_, index) => (
      <li key={index}>
        <img src="https://render.fineartamerica.com/images/rendered/default/poster/8/10/break/images/artworkimages/medium/3/3-csgo-putri-anggi.jpg" />
      </li>
    ))}
                </ul>

            </div>
         </div>
        </>
    )
}
